# Category: race_condition

import sqlite3
from typing import Dict

class FileAccessControl:
    def __init__(self, db_name: str):
        self.db_name = db_name
        self.conn = sqlite3.connect(db_name)
        self.cursor = self.conn.cursor()

    def query_database(self, user_id: int) -> int:
        self.cursor.execute("SELECT access_level FROM users WHERE id=?", (user_id,))
        return self.cursor.fetchone()[0]

    def check_permissions(self, file_path: str, user_id: int):
        access_level = self.query_database(user_id)
        if access_level > 2: # for example, let's say level 3 is owner and has all permissions
            raise PermissionError(f"User with ID {user_id} does not have permission to read file {file_path}")
        
    def open_file(self, file_path: str, user_id: int) -> bytes:
        self.check_permissions(file_path, user_id)
        try:
            with open(file_path, 'rb') as f:
                return f.read()
        except FileNotFoundError:
            raise FileNotFoundError(f"File not found: {file_path}")
        
    def close(self):
        self.conn.close()

